interface Transport { void deliver(); }

class Truck implements Transport {
    void deliver() { /* deliver by land */ }
}
class Ship implements Transport {
    void deliver() { /* deliver by sea */ }
}

abstract class Logistics {           // CREATOR
    abstract Transport createTransport();
    void planDelivery() {
        Transport t = createTransport();  // factory method call
        t.deliver();
    }
}

class RoadLogistics extends Logistics {  // CONCRETE CREATOR
    Transport createTransport() { return new Truck(); }
}
class SeaLogistics extends Logistics {
    Transport createTransport() { return new Ship(); }
}

interface Button {
    void render();
    void onClick(Runnable f);
}

class WindowsButton implements Button {
    public void render() { System.out.println("Windows button"); }
    public void onClick(Runnable f) { f.run(); }
}
class HTMLButton implements Button {
    public void render() { System.out.println("<button>HTML</button>"); }
    public void onClick(Runnable f) { f.run(); }
}

abstract class Dialog {                         // CREATOR
    public abstract Button createButton();       // FACTORY METHOD
    public void render() {
        Button btn = createButton();
        btn.onClick(() -> System.out.println("Closing..."));
        btn.render();
    }
}

class WindowsDialog extends Dialog {
    public Button createButton() { return new WindowsButton(); }
}
class WebDialog extends Dialog {
    public Button createButton() { return new HTMLButton(); }
}

interface Document {
    void open();
    void save();
}

class PDFDocument implements Document {
    public void open() { System.out.println("PDF: Rendering fonts..."); }
    public void save() { System.out.println("PDF: Exporting file..."); }
}
class WordDocument implements Document {
    public void open() { System.out.println("Word: Loading XML..."); }
    public void save() { System.out.println("Word: Updating docx..."); }
}

abstract class DocumentCreator {
    public abstract Document createDocument();  // FACTORY METHOD
    public void exportDocument() {
        Document doc = createDocument();
        doc.open();
        doc.save();
    }
}

class PDFExporter extends DocumentCreator {
    public Document createDocument() { return new PDFDocument(); }
}
class WordExporter extends DocumentCreator {
    public Document createDocument() { return new WordDocument(); }
}

#include <iostream>
#include <memory>

class Button {
public:
    virtual ~Button() = default;
    virtual void paint() = 0;
    virtual void onClick() = 0;
};

class WinButton : public Button {
public:
    void paint() override { std::cout << "Drawing Windows button\n"; }
    void onClick() override { std::cout << "Windows click!\n"; }
};
class MacButton : public Button {
public:
    void paint() override { std::cout << "Drawing macOS button\n"; }
    void onClick() override { std::cout << "macOS click!\n"; }
};

class GUIFramework {
public:
    virtual std::unique_ptr<Button> createButton() = 0;  // FACTORY METHOD
    void renderUI() {
        auto btn = createButton();
        btn->paint();
        btn->onClick();
    }
};

class WindowsUI : public GUIFramework {
public:
    std::unique_ptr<Button> createButton() override {
        return std::make_unique<WinButton>();
    }
};
class MacUI : public GUIFramework {
public:
    std::unique_ptr<Button> createButton() override {
        return std::make_unique<MacButton>();
    }
};

